<?php
/** License compliance queue for expiring and expired driver licenses. */
declare(strict_types=1);
require_once __DIR__.'/../../config/config.php';require_once ROOT_PATH.'/functions/driver_functions.php';requireAuth();enforceModuleAccess('drivers');$drivers=getDb()->query('SELECT id,full_name,license_number,license_expiry,status FROM drivers WHERE deleted_at IS NULL ORDER BY license_expiry ASC')->fetchAll();$pageTitle='License tracking';require ROOT_PATH.'/includes/header.php';require ROOT_PATH.'/includes/sidebar.php';
?><main class="main-content driver-module"><?php require ROOT_PATH.'/includes/navbar.php';?><h1 class="page-title">License tracking</h1><p class="page-subtitle">Prioritize expired and next-30-day compliance actions.</p><section class="card table-card"><div class="table-responsive"><table><thead><tr><th>Driver</th><th>License</th><th>Expiry</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($drivers as $driver):$status=driverLicenseStatus($driver['license_expiry']);?><tr><td><?=e($driver['full_name'])?></td><td><?=e($driver['license_number'])?></td><td><?=e(formatDate($driver['license_expiry']))?></td><td><span class="badge badge-<?=$status==='Valid'?'success':($status==='Expired'?'danger':'warning')?>"><?=e($status)?></span></td><td><a class="btn btn-secondary" href="edit.php?id=<?=$driver['id']?>">Update</a></td></tr><?php endforeach;?></tbody></table></div></section></main><?php require ROOT_PATH.'/includes/footer.php';?>
